<?php
/**
 * Plugin Name: DigiWin OG Image
 * Description: Adds Open Graph image for social sharing thumbnails
 */

// Write OG image file if it doesn't exist
add_action('init', function() {
    $upload_dir = wp_upload_dir();
    $og_path = $upload_dir['basedir'] . '/og-digiwin-thailand.png';
    if (!file_exists($og_path)) {
        $data = base64_decode('');
        if ($data) file_put_contents($og_path, $data);
    }
});

// Add og:image meta tag (runs before Yoast)
add_filter('wpseo_opengraph_image', function($img) {
    if (empty($img)) {
        $upload_dir = wp_upload_dir();
        return $upload_dir['baseurl'] . '/og-digiwin-thailand.png';
    }
    return $img;
});

// Fallback: add og:image directly if Yoast doesn't
add_action('wp_head', function() {
    // Check if Yoast already added og:image
    $upload_dir = wp_upload_dir();
    $og_url = $upload_dir['baseurl'] . '/og-digiwin-thailand.png';
    echo '<meta property="og:image" content="' . esc_url($og_url) . '" />' . "\n";
    echo '<meta property="og:image:width" content="1200" />' . "\n";
    echo '<meta property="og:image:height" content="630" />' . "\n";
}, 1);
